    <script>function shopManager(storeUrl){const empty=()=>({id:'',name:'',description:'',price:'',stock:0,active:'1',action:storeUrl});return{modal:false,mode:'create',form:empty(),newProduct(){this.mode='create';this.form=empty();this.open()},editProduct(p){this.mode='edit';this.form={...p,active:String(p.active)};this.open()},open(){this.modal=true;document.body.classList.add('overflow-hidden')},close(){this.modal=false;document.body.classList.remove('overflow-hidden')}}}</script>
